 28‚Üí		mcpgo.WithDescription("Search your knowledge base. Returns matching items with titles, types, tags, and content snippets."),
 29‚Üí		mcpgo.WithString("query", mcpgo.Required(), mcpgo.Description("Search query text")),
 30‚Üí		mcpgo.WithNumber("limit", mcpgo.Description("Max results to return (1-50, default 10)")),
 31‚Üí		mcpgo.WithString("type", mcpgo.Description("Filter by item type"), mcpgo.Enum("bookmark", "text_note", "voice_note")),
 32‚Üí	)
 33‚Üí}
