 35‚Üífunc searchHandler(deps Deps) server.ToolHandlerFunc {
 36‚Üí	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
 37‚Üí		claims, errResult := requireAuth(ctx)
 38‚Üí		if errResult != nil {
 39‚Üí			return errResult, nil
 40‚Üí		}
 41‚Üí
 42‚Üí		if errResult := AllowedTool(ctx, "search"); errResult != nil {
 43‚Üí			auditToolCall(ctx, deps.Audit, claims, "search", req.GetArguments(), true)
 44‚Üí			return errResult, nil
 45‚Üí		}
 46‚Üí
 47‚Üí		query := req.GetString("query", "")
 48‚Üí		if query == "" {
 49‚Üí			return mcpgo.NewToolResultError("query is required"), nil
 50‚Üí		}
 51‚Üí
 52‚Üí		limit := req.GetInt("limit", defaultSearchLimit)
 53‚Üí		if limit < 1 {
 54‚Üí			limit = 1
 55‚Üí		}
 56‚Üí		if limit > maxSearchLimit {
 57‚Üí			limit = maxSearchLimit
 58‚Üí		}
 59‚Üí
 60‚Üí		var filter *item.Filter
 61‚Üí		if t := req.GetString("type", ""); t != "" {
 62‚Üí			filter = &item.Filter{Types: []string{t}}
 63‚Üí		}
 64‚Üí
 65‚Üí		result, err := doSearch(ctx, deps, claims.UserID, query, filter, limit)
 66‚Üí		if err != nil {
 67‚Üí			auditToolCall(ctx, deps.Audit, claims, "search", req.GetArguments(), false)
 68‚Üí			return mcpgo.NewToolResultError(fmt.Sprintf("search failed: %v", err)), nil
 69‚Üí		}
 70‚Üí
 71‚Üí		// Filter results by sensitivity
 72‚Üí		result = FilterItemsBySensitivity(ctx, result)
 73‚Üí
 74‚Üí		auditToolCall(ctx, deps.Audit, claims, "search", req.GetArguments(), false)
 75‚Üí		return mcpgo.NewToolResultText(formatSearchResults(result)), nil
 76‚Üí	}
 77‚Üí}
