 79‚Üí// doSearch tries semantic search first, falling back to full-text search.
 80‚Üífunc doSearch(ctx context.Context, deps Deps, ownerID uuid.UUID, query string, filter *item.Filter, limit int) (*item.SearchResult, error) {
 81‚Üí	if deps.Embedder != nil {
 82‚Üí		embedding, err := deps.Embedder.Embed(ctx, query)
 83‚Üí		if err != nil {
 84‚Üí			slog.WarnContext(ctx, "mcp: embedding failed, falling back to FTS", "error", err)
 85‚Üí		} else {
 86‚Üí			result, err := deps.Items.SemanticSearch(ctx, ownerID, embedding, filter, limit, defaultSearchThreshold)
 87‚Üí			if err == nil && len(result.Items) > 0 {
 88‚Üí				return result, nil
 89‚Üí			}
 90‚Üí			if err != nil {
 91‚Üí				slog.WarnContext(ctx, "mcp: semantic search failed, falling back to FTS", "error", err)
 92‚Üí			}
 93‚Üí		}
 94‚Üí	}
 95‚Üí
 96‚Üí	return deps.Items.Search(ctx, ownerID, query, filter, limit, 0)
 97‚Üí}
