import { test, expect } from '@playwright/test'

const isManual = process.env.DEMO_MODE === 'manual'

test.describe('Web Walkthrough', () => {
  test.describe.configure({ mode: 'serial' })

  test('Home page ‚Äî hero and feature cards', async ({ page }) => {
    await page.goto('/')
    await expect(page.getByText('Your second brain')).toBeVisible()

    // Feature cards are present
    await expect(page.getByText('Bookmarks')).toBeVisible()
    await expect(page.getByText('Semantic Search')).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Login with seed credentials', async ({ page }) => {
    await page.goto('/login')
    await page.getByLabel('Email').fill('ketan@example.com')
    await page.getByLabel('Password').fill('testpassword123')
    await page.getByRole('button', { name: 'Login' }).click()

    // Authenticated state ‚Äî Capture button appears in header
    await expect(page.getByRole('button', { name: 'Capture' })).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Browse ‚Äî seeded items visible', async ({ page }) => {
    // Login first
    await page.goto('/login')
    await page.getByLabel('Email').fill('ketan@example.com')
    await page.getByLabel('Password').fill('testpassword123')
    await page.getByRole('button', { name: 'Login' }).click()
    await expect(page.getByRole('button', { name: 'Capture' })).toBeVisible()

    await page.goto('/browse')
    await page.waitForLoadState('networkidle')

    // Verify known seed item titles appear
    await expect(page.getByText('Sourdough bread recipe')).toBeVisible()
    await expect(page.getByText('Go Performance Optimization')).toBeVisible()

    // Type badges render
    await expect(page.getByText('bookmark').first()).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Search ‚Äî find sourdough recipe', async ({ page }) => {
    // Login first
    await page.goto('/login')
    await page.getByLabel('Email').fill('ketan@example.com')
    await page.getByLabel('Password').fill('testpassword123')
    await page.getByRole('button', { name: 'Login' }).click()
    await expect(page.getByRole('button', { name: 'Capture' })).toBeVisible()

    await page.goto('/search')

    // Enter search query and submit
    const searchInput = page.getByRole('textbox')
    await searchInput.fill('sourdough')
    await searchInput.press('Enter')

    // Wait for results
    await expect(page.getByText('Sourdough bread recipe')).toBeVisible()

    if (isManual) await page.pause()
  })

  test('Item detail ‚Äî title, content, tags, metadata', async ({ page }) => {
    // Login first
    await page.goto('/login')
    await page.getByLabel('Email').fill('ketan@example.com')
    await page.getByLabel('Password').fill('testpassword123')
    await page.getByRole('button', { name: 'Login' }).click()
    await expect(page.getByRole('button', { name: 'Capture' })).toBeVisible()

    // Search for a known item and click into it
    await page.goto('/search')
    const searchInput = page.getByRole('textbox')
    await searchInput.fill('sourdough')
    await searchInput.press('Enter')
    await expect(page.getByText('Sourdough bread recipe')).toBeVisible()
    await page.getByText('Sourdough bread recipe').click()

